    // myref has TYPE int&&
    std::cout << "myref type is rvalue reference: "
              << std::is_rvalue_reference<decltype(myref)>::value << "\n";

    // But myref as EXPRESSION is lvalue
    analyze(std::move(myref));  // Must use std::move to pass it
}

